     1→/**
     2→ * Mobile Server Middleware - CORS, auth, rate limiting
     3→ */
     4→
     5→import { Express, Request, Response, NextFunction } from 'express'
     6→import cors from 'cors'
     7→import express from 'express'
     8→import { existsSync } from 'fs'
     9→import {
    10→  classifyIp,
    11→  getClientIp,
    12→  checkRateLimit,
    13→  recordFailedAuth,
    14→  clearRateLimit,
    15→  checkEndpointRateLimit,
    16→  IpClass
    17→} from '../mobile-security'
    18→import { log, isStaticPath } from './utils'
    19→import { EndpointAccess } from './types'
    20→
    21→export function setupCorsMiddleware(app: Express): void {
    22→  app.use(cors({
    23→    origin: (origin, callback) => {
    24→      // Allow requests with no origin (same-origin, mobile apps, curl, etc.)
    25→      if (!origin) {
    26→        return callback(null, true)
    27→      }
    28→
    29→      // Allow capacitor:// and file:// schemes (mobile app)
    30→      if (origin.startsWith('capacitor://') || origin.startsWith('file://')) {
    31→        return callback(null, true)
    32→      }
    33→
    34→      // Parse origin to extract hostname for safe validation
    35→      let hostname: string
    36→      try {
    37→        hostname = new URL(origin).hostname
    38→      } catch {
    39→        log('CORS blocked malformed origin', { origin })
    40→        return callback(new Error('CORS not allowed for this origin'))
    41→      }
    42→
    43→      // Allow localhost variants
    44→      if (hostname === 'localhost' || hostname === '127.0.0.1') {
    45→        return callback(null, true)
    46→      }
    47→
    48→      // Allow local network IP ranges (RFC 1918)
    49→      // 10.x.x.x, 192.168.x.x, 172.16-31.x.x
    50→      const localNetworkPattern = /^(10\.\d+\.\d+\.\d+|192\.168\.\d+\.\d+|172\.(1[6-9]|2\d|3[01])\.\d+\.\d+)$/
    51→      if (localNetworkPattern.test(hostname)) {
    52→        return callback(null, true)
    53→      }
    54→
    55→      // Allow Tailscale CGNAT range (100.64.0.0 - 100.127.255.255)
    56→      const tailscaleCgnatPattern = /^100\.(6[4-9]|[7-9]\d|1[01]\d|12[0-7])\.\d+\.\d+$/
    57→      if (tailscaleCgnatPattern.test(hostname)) {
    58→        return callback(null, true)
    59→      }
    60→
    61→      // Allow Tailscale MagicDNS hostnames (*.ts.net)
    62→      if (hostname.endsWith('.ts.net')) {
    63→        return callback(null, true)
    64→      }
    65→
    66→      // Reject other origins
    67→      log('CORS blocked origin', { origin })
    68→      callback(new Error('CORS not allowed for this origin'))
    69→    },
    70→    credentials: true
    71→  }))
    72→}
    73→
    74→export function setupStaticMiddleware(app: Express, rendererPath: string): void {
    75→  log('Static files path:', { path: rendererPath, exists: existsSync(rendererPath) })
    76→  if (existsSync(rendererPath)) {
    77→    app.use(express.static(rendererPath, {
    78→      index: 'index.html'
    79→    }))
    80→  }
    81→}
    82→
    83→export function setupJsonMiddleware(app: Express): void {
    84→  app.use(express.json({ limit: '1mb' }))
    85→}
    86→
    87→export function setupRateLimitMiddleware(app: Express): void {
    88→  app.use((req: Request, res: Response, next: NextFunction) => {
    89→    const clientIp = getClientIp(req)
    90→    const rateLimit = checkRateLimit(clientIp)
    91→
    92→    if (!rateLimit.allowed) {
    93→      return res.status(429).json({
    94→        error: 'Too many failed attempts. Please try again later.',
    95→        retryAfter: rateLimit.retryAfter
    96→      }).setHeader('Retry-After', String(rateLimit.retryAfter || 900))
    97→    }
    98→
    99→    next()
   100→  })
   101→}
   102→
   103→export function setupAuthMiddleware(app: Express, getToken: () => string): void {
   104→  app.use((req: Request, res: Response, next: NextFunction) => {
   105→    // Skip auth for unauthenticated endpoints
   106→    if (req.path === '/health' || req.path === '/connect' || req.path === '/verify-handshake') {
   107→      return next()
   108→    }
   109→
   110→    // /ws-test uses query string auth (validates token itself)
   111→    if (req.path === '/ws-test') {
   112→      const queryToken = req.query.token as string
   113→      if (queryToken === getToken()) {
   114→        return next()
   115→      }
   116→      // Let the route handler return the proper error
   117→      return next()
   118→    }
   119→    // Skip auth for static files (token passed in query string for initial load)
   120→    if (isStaticPath(req.path)) {
   121→      const queryToken = req.query.token as string
   122→      if (queryToken === getToken()) {
   123→        return next()
   124→      }
   125→      // Check cookie for subsequent static file requests
   126→      const cookieToken = req.headers.cookie?.split(';')
   127→        .map(c => c.trim())
   128→        .find(c => c.startsWith('ct_token='))
   129→        ?.split('=')[1]
   130→      if (cookieToken === getToken()) {
   131→        return next()
   132→      }
   133→      // No valid token - still serve static files but without sensitive data
   134→      return next()
   135→    }
   136→
   137→    const clientIp = getClientIp(req)
   138→
   139→    // Allow query token for file downloads (needed for Android WebView window.open)
   140→    if (req.path.startsWith('/api/files/')) {
   141→      const queryToken = req.query.token as string
   142→      if (queryToken === getToken()) {
   143→        clearRateLimit(clientIp)
   144→        return next()
   145→      }
   146→    }
   147→
   148→    const authHeader = req.headers.authorization
   149→    if (!authHeader || !authHeader.startsWith('Bearer ')) {
   150→      recordFailedAuth(clientIp)
   151→      return res.status(401).json({ error: 'Missing authorization header' })
   152→    }
   153→
   154→    const providedToken = authHeader.slice(7)
   155→    if (providedToken !== getToken()) {
   156→      const blocked = recordFailedAuth(clientIp)
   157→      if (blocked) {
   158→        return res.status(429).json({
   159→          error: 'Too many failed attempts. Please try again later.',
   160→          retryAfter: 900
   161→        })
   162→      }
   163→      return res.status(403).json({ error: 'Invalid token' })
   164→    }
   165→
   166→    // Successful auth - clear rate limit
   167→    clearRateLimit(clientIp)
   168→
   169→    next()
   170→  })
   171→}
   172→
   173→export function getEndpointAccessLevel(path: string, method: string): EndpointAccess {
   174→  // Settings: GET is read (allows mobile to load theme), POST is admin-only
   175→  if (path.includes('/api/settings')) {
   176→    return method === 'GET' ? 'read' : 'admin'
   177→  }
   178→
   179→  // Terminal and write operations need write access
   180→  if (path.includes('/api/terminal')) {
   181→    return 'write'
   182→  }
   183→
   184→  // PTY operations need write access
   185→  if (path.includes('/api/pty')) {
   186→    return 'write'
   187→  }
   188→
   189→  // Workspace POST/PUT needs write, GET needs read
   190→  if (path === '/api/workspace') {
   191→    return method === 'GET' ? 'read' : 'write'
   192→  }
   193→
   194→  // Project add needs write access
   195→  if (path === '/api/project/add') {
   196→    return 'write'
   197→  }
   198→
   199→  // Sessions discovery is read-only
   200→  if (path === '/api/sessions') {
   201→    return 'read'
   202→  }
   203→
   204→  // Beads: GET operations are read, write operations need write access
   205→  if (path.includes('/projects/beads')) {
   206→    if (method === 'GET') {
   207→      return 'read'
   208→    }
   209→    return 'write'
   210→  }
   211→
   212→  // TTS speak/stop/settings need write
   213→  if (path.includes('/api/tts/speak') || path.includes('/api/tts/stop') || path.includes('/api/tts/settings')) {
   214→    return 'write'
   215→  }
   216→
   217→  // File operations: restricted to local network for security
   218→  if (path.includes('/api/files')) {
   219→    return 'write'
   220→  }
   221→
   222→  // Default to read for other authenticated endpoints
   223→  return 'read'
   224→}
   225→
   226→export function isAccessAllowed(ipClass: IpClass, access: EndpointAccess): boolean {
   227→  switch (access) {
   228→    case 'admin':
   229→      return ipClass === 'localhost'
   230→    case 'write':
   231→      return ipClass === 'localhost' || ipClass === 'local_network'
   232→    case 'read':
   233→      return true
   234→    default:
   235→      return false
   236→  }
   237→}
   238→
   239→export function setupIpAccessMiddleware(app: Express): void {
   240→  app.use((req: Request, res: Response, next: NextFunction) => {
   241→    // Skip for unauthenticated endpoints and static files
   242→    if (req.path === '/health' || req.path === '/connect' || req.path === '/verify-handshake' || req.path === '/ws-test') {
   243→      return next()
   244→    }
   245→    if (isStaticPath(req.path)) {
   246→      return next()
   247→    }
   248→
   249→    const clientIp = getClientIp(req)
   250→    const ipClass = classifyIp(clientIp)
   251→
   252→    // Determine required access level for this endpoint
   253→    const accessLevel = getEndpointAccessLevel(req.path, req.method)
   254→
   255→    // Check if IP class is allowed for this access level
   256→    if (!isAccessAllowed(ipClass, accessLevel)) {
   257→      return res.status(403).json({
   258→        error: `This operation requires ${accessLevel} access. Your IP (${ipClass}) is not authorized.`
   259→      })
   260→    }
   261→
   262→    next()
   263→  })
   264→}
   265→
   266→export function setupEndpointRateLimitMiddleware(app: Express): void {
   267→  app.use((req: Request, res: Response, next: NextFunction) => {
   268→    // Skip for health check, ws-test, and static files
   269→    if (req.path === '/health' || req.path === '/ws-test' || isStaticPath(req.path)) {
   270→      return next()
   271→    }
   272→
   273→    const clientIp = getClientIp(req)
   274→    const result = checkEndpointRateLimit(clientIp, req.method, req.path)
   275→
   276→    // Add rate limit headers
   277→    res.setHeader('X-RateLimit-Remaining', String(result.remaining))
   278→    res.setHeader('X-RateLimit-Reset', String(Math.ceil(result.resetIn / 1000)))
   279→
   280→    if (!result.allowed) {
   281→      return res.status(429).json({
   282→        error: 'Too many requests. Please slow down.',
   283→        retryAfter: Math.ceil(result.resetIn / 1000)
   284→      }).setHeader('Retry-After', String(Math.ceil(result.resetIn / 1000)))
   285→    }
   286→
   287→    next()
   288→  })
   289→}
